using Microsoft.UI.Xaml; using Microsoft.UI.Xaml.Controls;
namespace FlyPPTTimer.WinUI.Pages;
public sealed partial class PowerPointPage : Page { public PowerPointPage(){InitializeComponent();DataContext=App.Services.ViewModel;} private void Restart_Click(object s,RoutedEventArgs e)=>App.Services.ViewModel.RestartPowerPoint(); private async void Goto_Click(object s,RoutedEventArgs e)=>await App.Services.ViewModel.GoToSlide((int)SlideBox.Value); private async void Open_Click(object s,RoutedEventArgs e){if(s is Button b&&b.Tag is string id)await App.Services.ViewModel.OpenPresentation(id,false);} private async void EndShow_Click(object s,RoutedEventArgs e){var d=new ContentDialog{Title="结束放映？",Content="当前 PowerPoint 放映将结束。",PrimaryButtonText="结束",CloseButtonText="取消",XamlRoot=XamlRoot};if(await d.ShowAsync()==ContentDialogResult.Primary)await App.Services.Controller.ExecutePresentationAsync(new("ppt.endShow"));} }
